const owner = 'REPLACE_WITH_GITHUB_USERNAME';
const repo = 'REPLACE_WITH_REPO_NAME';
const workflowId = 'run_clara_pipeline.yml';
const ref = 'main';
const token = 'REPLACE_WITH_GITHUB_PAT';

if (
  owner.startsWith('REPLACE_') ||
  repo.startsWith('REPLACE_') ||
  token.startsWith('REPLACE_')
) {
  throw new Error('Update owner/repo/token placeholders in this node before running.');
}

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.github.com/repos/${owner}/${repo}/actions/workflows/${workflowId}/dispatches`,
  headers: {
    Authorization: `Bearer ${token}`,
    Accept: 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28'
  },
  body: { ref },
  json: true,
  resolveWithFullResponse: true,
  simple: false
});

return [
  {
    json: {
      owner,
      repo,
      workflow_id: workflowId,
      ref,
      status_code: response.statusCode,
      dispatched: response.statusCode === 204,
      message: response.statusCode === 204
        ? 'Pipeline run dispatched. Check GitHub Actions for progress and artifacts.'
        : 'Unexpected response. Check token scopes and repository settings.'
    }
  }
];
